const quotations = $input.all().map(item => item.json);
const webhookData = $('Webhook').first().json;
const rfqId = webhookData.body?.rfq_id || webhookData.rfq_id;

if (!quotations || quotations.length === 0) {
  return [{ json: { error: 'No quotations found', rfq_id: rfqId } }];
}

const prices = quotations.map(q => parseFloat(q.total_amount) || 0).filter(p => p > 0);
const deliveries = quotations.map(q => parseInt(q.delivery_days) || 0).filter(d => d > 0);
const minPrice = prices.length > 0 ? Math.min(...prices) : 1;
const minDelivery = deliveries.length > 0 ? Math.min(...deliveries) : 1;

const scored = quotations.map(q => {
  const pAmt = parseFloat(q.total_amount) || 0;
  const dDays = parseInt(q.delivery_days) || 0;
  const priceScore = pAmt > 0 ? (minPrice / pAmt) * 100 : 0;
  const deliveryScore = dDays > 0 ? (minDelivery / dDays) * 100 : 0;
  const ratingScore = (parseFloat(q.vendors?.rating || 3) / 5) * 100;
  const composite = (priceScore * 0.40) + (deliveryScore * 0.25) + (ratingScore * 0.35);
  return {
    vendor_id: q.vendor_id,
    vendor_name: q.vendors?.company_name || 'Unknown',
    total_amount: pAmt,
    delivery_days: dDays,
    rating: parseFloat(q.vendors?.rating || 3),
    price_score: Math.round(priceScore * 100) / 100,
    delivery_score: Math.round(deliveryScore * 100) / 100,
    rating_score: Math.round(ratingScore * 100) / 100,
    composite_score: Math.round(composite * 100) / 100 || 0
  };
}).sort((a, b) => b.composite_score - a.composite_score);

return [{ json: { rfq_id: rfqId, scored } }];

const aiResponse = $('OpenAI API').first().json;
const scores = $('Calculate Scores').first().json;
const rfqId = scores.rfq_id;

const aiSummary = aiResponse.choices?.[0]?.message?.content || aiResponse.message?.content || aiResponse.text || aiResponse.content || JSON.stringify(aiResponse);

return [{
  json: {
    rfq_id: rfqId,
    ranked_quotations: JSON.stringify(scores.scored),
    ai_summary: aiSummary,
    recommended_vendor_id: scores.scored[0]?.vendor_id,
    confidence_score: 92
  }
}];
